    }
  }

  return {
    isOpen: true,
    opensAt: event.submissionOpensAt,
    closesAt: event.submissionClosesAt,
  }
}

/**
 * Resolve which divisionId to scope a score read/write to. When the caller
 * supplies a divisionId, verify the user is actually registered in it. Otherwise,
 * if the user has exactly one active registration, use that division. If they
 * have multiple registrations and none was specified, return null so the caller
 * can decide how to handle the ambiguity (error vs. "any of their divisions").
 */
async function resolveAthleteDivisionId({
  competitionId,
  userId,
  requestedDivisionId,
}: {
  competitionId: string
  userId: string
  requestedDivisionId?: string
}): Promise<string | null> {
  const db = getDb()

  const baseConditions = [
    eq(competitionRegistrationsTable.eventId, competitionId),
    eq(competitionRegistrationsTable.userId, userId),
    ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
  ]

  if (requestedDivisionId) {
    const [reg] = await db
      .select({ divisionId: competitionRegistrationsTable.divisionId })
      .from(competitionRegistrationsTable)
      .where(
        and(
          ...baseConditions,
          eq(competitionRegistrationsTable.divisionId, requestedDivisionId),
        ),
      )
      .limit(1)
    return reg?.divisionId ?? null
  }

  const regs = await db
    .select({ divisionId: competitionRegistrationsTable.divisionId })
    .from(competitionRegistrationsTable)
    .where(and(...baseConditions))
    .limit(2)

  if (regs.length === 1) return regs[0].divisionId ?? null
  return null
}

// ============================================================================
// Server Functions
// ============================================================================

/**
 * Get the submission window status for an event
 */
export const getSubmissionWindowStatusFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getSubmissionWindowInputSchema.parse(data))
  .handler(async ({ data }): Promise<SubmissionWindowStatus> => {
    return checkSubmissionWindow(data.competitionId, data.trackWorkoutId)
  })

/**
 * Get the athlete's existing score for an event
 */
export const getAthleteEventScoreFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getScoreInputSchema.parse(data))
  .handler(async ({ data }): Promise<AthleteEventScore> => {
    const session = await getSessionFromCookie()
    if (!session?.userId) {
      logWarning({
        message: "[AthleteScore] Get score denied - not authenticated",
        attributes: {
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
        },
      })
      throw new Error("Not authenticated")
    }

    // Update request context
    updateRequestContext({ userId: session.userId })
    addRequestContextAttribute("competitionId", data.competitionId)
    addRequestContextAttribute("trackWorkoutId", data.trackWorkoutId)

    const db = getDb()

    // Resolve the athlete's division for this competition. When an athlete is
    // registered in multiple divisions that share a workout, scores are keyed
    // per-division — pick the right row by scoping to divisionId.
    const resolvedDivisionId = await resolveAthleteDivisionId({
      competitionId: data.competitionId,
      userId: session.userId,
      requestedDivisionId: data.divisionId,
    })

    const scoreConditions = [
      eq(scoresTable.competitionEventId, data.trackWorkoutId),
      eq(scoresTable.userId, session.userId),
    ]
    if (resolvedDivisionId) {
      scoreConditions.push(eq(scoresTable.scalingLevelId, resolvedDivisionId))
    }

    // Get the user's existing score for this event (division-scoped)
    const [existingScore] = await db
      .select({
        id: scoresTable.id,
        scoreValue: scoresTable.scoreValue,
        status: scoresTable.status,
        secondaryValue: scoresTable.secondaryValue,
        tiebreakValue: scoresTable.tiebreakValue,
        recordedAt: scoresTable.recordedAt,
        scheme: scoresTable.scheme,
      })
      .from(scoresTable)
      .where(and(...scoreConditions))
      .limit(1)

    if (!existingScore) {
      return {
        scoreId: null,
        scoreValue: null,
        displayScore: null,
        status: null,
        secondaryValue: null,
        tiebreakValue: null,
        submittedAt: null,
      }
    }

    // Decode the score for display
    const { decodeScore } = await import("@/lib/scoring")
    let displayScore: string | null = null
    if (existingScore.scoreValue !== null) {
      displayScore = decodeScore(
        existingScore.scoreValue,
        existingScore.scheme as WorkoutScheme,
        { compact: false },
      )
    }

    return {
      scoreId: existingScore.id,
      scoreValue: existingScore.scoreValue,
      displayScore,
      status: existingScore.status,
      secondaryValue: existingScore.secondaryValue,
      tiebreakValue: existingScore.tiebreakValue,
      submittedAt: existingScore.recordedAt,
    }
  })

/**
 * Submit or update an athlete's score for an event
 */
export const submitAthleteScoreFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) => submitScoreInputSchema.parse(data))
  .handler(
    async ({
      data,
    }): Promise<{
      success: boolean
      scoreId: string
      message: string
    }> => {
      const session = await getSessionFromCookie()
      if (!session?.userId) {
        logWarning({
          message: "[AthleteScore] Submission denied - not authenticated",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
          },
        })
        throw new Error("Not authenticated")
      }

      const db = getDb()

      // Update request context
      updateRequestContext({ userId: session.userId })
      addRequestContextAttribute("competitionId", data.competitionId)
      addRequestContextAttribute("trackWorkoutId", data.trackWorkoutId)

      logInfo({
        message: "[AthleteScore] Score submission started",
        attributes: {
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
          userId: session.userId,
          status: data.status,
        },
      })

      // 1. Resolve the registration scoped to the division the athlete is
      // submitting for. If divisionId is provided, match it exactly. Otherwise,
      // only proceed when the user has a single registration — ambiguity between
      // multi-division registrations would silently write to the wrong division.
      const regConditions = [
        eq(competitionRegistrationsTable.eventId, data.competitionId),
        eq(competitionRegistrationsTable.userId, session.userId),
        ne(competitionRegistrationsTable.status, REGISTRATION_STATUS.REMOVED),
      ]
      if (data.divisionId) {
        regConditions.push(
          eq(competitionRegistrationsTable.divisionId, data.divisionId),
        )
      }

      const registrations = await db
        .select({
          id: competitionRegistrationsTable.id,
          divisionId: competitionRegistrationsTable.divisionId,
        })
        .from(competitionRegistrationsTable)
        .where(and(...regConditions))
        .limit(2)

      if (registrations.length === 0) {
        logWarning({
          message: "[AthleteScore] Submission denied - not registered",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
            divisionId: data.divisionId ?? null,
          },
        })
        throw new Error("You are not registered for this competition")
      }

      if (registrations.length > 1) {
        logWarning({
          message: "[AthleteScore] Submission denied - ambiguous division",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
          },
        })
        throw new Error(
          "You are registered in multiple divisions for this competition. Please specify which division to submit for.",
        )
      }

      const registration = registrations[0]
      addRequestContextAttribute("registrationId", registration.id)

      // 2. Check submission window
      const windowStatus = await checkSubmissionWindow(
        data.competitionId,
        data.trackWorkoutId,
      )

      if (!windowStatus.isOpen) {
        logWarning({
          message: "[AthleteScore] Submission window blocked",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
            reason: windowStatus.reason,
            opensAt: windowStatus.opensAt,
            closesAt: windowStatus.closesAt,
          },
        })
        throw new Error(windowStatus.reason || "Submission window is not open")
      }

      // 3. Get workout info for proper encoding
      const [trackWorkout] = await db
        .select({
          workoutId: trackWorkoutsTable.workoutId,
          trackId: trackWorkoutsTable.trackId,
        })
        .from(trackWorkoutsTable)
        .where(eq(trackWorkoutsTable.id, data.trackWorkoutId))
        .limit(1)

      if (!trackWorkout) {
        throw new Error("Event not found")
      }

      const [workout] = await db
        .select({
          scheme: workouts.scheme,
          scoreType: workouts.scoreType,
          tiebreakScheme: workouts.tiebreakScheme,
          timeCap: workouts.timeCap,
        })
        .from(workouts)
        .where(eq(workouts.id, trackWorkout.workoutId))
        .limit(1)

      if (!workout) {
        throw new Error("Workout not found")
      }

      const scheme = workout.scheme as WorkoutScheme
      const scoreType =
        (workout.scoreType as ScoreType) || getDefaultScoreType(scheme)

      // 4. Parse and validate the score
      const parseResult = parseScore(data.score, scheme)
      if (!parseResult.isValid) {
        logWarning({
          message: "[AthleteScore] Invalid score format",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
            score: data.score,
            scheme,
            error: parseResult.error,
          },
        })
        throw new Error(
          `Invalid score format: ${parseResult.error || "Please check your entry"}`,
        )
      }

      // Encode the score
      let encodedValue: number | null = encodeScore(data.score, scheme)

      // Handle CAP status for time-with-cap workouts
      if (
        data.status === "cap" &&
        scheme === "time-with-cap" &&
        workout.timeCap
      ) {
        encodedValue = workout.timeCap * 1000 // Time cap in milliseconds
      }

      // Parse secondary score (reps at cap)
      let secondaryValue: number | null = null
      if (data.secondaryScore && data.status === "cap") {
        const parsed = Number.parseInt(data.secondaryScore.trim(), 10)
        if (!Number.isNaN(parsed) && parsed >= 0) {
          secondaryValue = parsed
        }
      }

      // Parse tiebreak score
      let tiebreakValue: number | null = null
      if (data.tiebreakScore && workout.tiebreakScheme) {
        tiebreakValue = encodeScore(
          data.tiebreakScore,
          workout.tiebreakScheme as WorkoutScheme,
        )
      }

      // Time cap in milliseconds
      const timeCapMs = workout.timeCap ? workout.timeCap * 1000 : null

      // Compute sort key
      const sortKey =
        encodedValue !== null
          ? computeSortKey({
              value: encodedValue,
              status: data.status,
              scheme,
              scoreType,
            })
          : null

      // 5. Get teamId from track
      const [track] = await db
        .select({
          ownerTeamId: programmingTracksTable.ownerTeamId,
        })
        .from(programmingTracksTable)
        .where(eq(programmingTracksTable.id, trackWorkout.trackId))
        .limit(1)

      if (!track?.ownerTeamId) {
        throw new Error("Could not determine team ownership")
      }

      // 6. Upsert the score
      await db
        .insert(scoresTable)
        .values({
          userId: session.userId,
          teamId: track.ownerTeamId,
          workoutId: trackWorkout.workoutId,
          competitionEventId: data.trackWorkoutId,
          scheme,
          scoreType,
          scoreValue: encodedValue,
          status: data.status,
          statusOrder: getStatusOrder(data.status),
          sortKey: sortKey ? sortKeyToString(sortKey) : null,
          tiebreakScheme: (workout.tiebreakScheme as TiebreakScheme) ?? null,
          tiebreakValue,
          timeCapMs,
          secondaryValue,
          scalingLevelId: registration.divisionId,
          asRx: true,
          recordedAt: new Date(),
        })
        .onDuplicateKeyUpdate({
          set: {
            scoreValue: encodedValue,
            status: data.status,
            statusOrder: getStatusOrder(data.status),
            sortKey: sortKey ? sortKeyToString(sortKey) : null,
            tiebreakScheme: (workout.tiebreakScheme as TiebreakScheme) ?? null,
            tiebreakValue,
            timeCapMs,
            secondaryValue,
            scalingLevelId: registration.divisionId,
            updatedAt: new Date(),
          },
        })

      // Get the final score ID — scope by division to match the 3-col unique key
      const finalScoreConditions = [
        eq(scoresTable.competitionEventId, data.trackWorkoutId),
        eq(scoresTable.userId, session.userId),
      ]
      if (registration.divisionId) {
        finalScoreConditions.push(
          eq(scoresTable.scalingLevelId, registration.divisionId),
        )

      }
      const [finalScore] = await db
        .select({ id: scoresTable.id })
        .from(scoresTable)
        .where(and(...finalScoreConditions))
        .limit(1)

      if (!finalScore) {
        logError({
          message: "[AthleteScore] Failed to retrieve score after upsert",
          attributes: {
            competitionId: data.competitionId,
            trackWorkoutId: data.trackWorkoutId,
            userId: session.userId,
          },
        })
        throw new Error("Failed to save score")
      }

      addRequestContextAttribute("scoreId", finalScore.id)
      logEntityUpdated({
        entity: "athleteScore",
        id: finalScore.id,
        attributes: {
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
          userId: session.userId,
          registrationId: registration.id,
          status: data.status,
        },
      })

      logInfo({
        message: "[AthleteScore] Score submitted successfully",
        attributes: {
          scoreId: finalScore.id,
          competitionId: data.competitionId,
          trackWorkoutId: data.trackWorkoutId,
          userId: session.userId,
          status: data.status,
        },
      })

      return {
        success: true,
        scoreId: finalScore.id,
        message: "Score submitted successfully",
      }
    },
  )

/**
 * Get workout details needed for score submission UI
 */
export const getEventWorkoutDetailsFn = createServerFn({ method: "GET" })
  .inputValidator((data: unknown) => getScoreInputSchema.parse(data))
  .handler(
    async ({
      data,
    }): Promise<{
      workoutId: string
      name: string
      scheme: WorkoutScheme
      scoreType: ScoreType | null
      timeCap: number | null
      tiebreakScheme: string | null
      repsPerRound: number | null
    }> => {
      const db = getDb()

      const [result] = await db
        .select({
          workoutId: workouts.id,
          name: workouts.name,
          scheme: workouts.scheme,
          scoreType: workouts.scoreType,
          timeCap: workouts.timeCap,
          tiebreakScheme: workouts.tiebreakScheme,
          repsPerRound: workouts.repsPerRound,
        })
        .from(trackWorkoutsTable)
        .innerJoin(workouts, eq(trackWorkoutsTable.workoutId, workouts.id))
        .where(eq(trackWorkoutsTable.id, data.trackWorkoutId))
        .limit(1)

      if (!result) {
        throw new Error("Event not found")
      }

      return {
        workoutId: result.workoutId,
        name: result.name,
        scheme: result.scheme as WorkoutScheme,
        scoreType: result.scoreType as ScoreType | null,
        timeCap: result.timeCap,
        tiebreakScheme: result.tiebreakScheme,
        repsPerRound: result.repsPerRound,
      }
    },
  )

