// ============================================================================
// Input Schemas
// ============================================================================

const submitScoreInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
  divisionId: z.string().optional(),
  score: z.string().min(1, "Score is required"),
  status: z.enum(["scored", "cap"]),
  secondaryScore: z.string().optional(),
  tiebreakScore: z.string().optional(),
})

const getScoreInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
  divisionId: z.string().optional(),
})

const getSubmissionWindowInputSchema = z.object({
  competitionId: z.string().min(1),
  trackWorkoutId: z.string().min(1),
})

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Map status to the simplified type for scores table.
 */
function getStatusOrder(status: "scored" | "cap"): number {
  switch (status) {
    case "scored":
      return STATUS_ORDER.scored
    case "cap":
      return STATUS_ORDER.cap
    default:
      return STATUS_ORDER.scored
  }
}

/**
 * Check if current time is within the event's submission window.
 */
async function checkSubmissionWindow(
  competitionId: string,
  trackWorkoutId: string,
): Promise<SubmissionWindowStatus> {
  const db = getDb()

  // Get competition type
  const [competition] = await db
    .select({
      competitionType: competitionsTable.competitionType,
    })
    .from(competitionsTable)
    .where(eq(competitionsTable.id, competitionId))
    .limit(1)

  if (!competition) {
    return {
      isOpen: false,
      opensAt: null,
      closesAt: null,
      reason: "Competition not found",
    }
  }

  // Only check submission windows for online competitions
  if (competition.competitionType !== "online") {
    return {
      isOpen: false,
      opensAt: null,
      closesAt: null,
      reason: "This is not an online competition",
    }
  }

  // Get competition event with submission window
  const [event] = await db
    .select({
      submissionOpensAt: competitionEventsTable.submissionOpensAt,
      submissionClosesAt: competitionEventsTable.submissionClosesAt,
    })
    .from(competitionEventsTable)
    .where(
      and(
        eq(competitionEventsTable.competitionId, competitionId),
        eq(competitionEventsTable.trackWorkoutId, trackWorkoutId),
      ),
    )
    .limit(1)

  // If no event record exists, submission not configured
  if (!event) {
    return {
      isOpen: false,
      opensAt: null,
      closesAt: null,
      reason: "Submission window not configured",
    }
  }

  // If no submission window is configured, submission not allowed
  if (!event.submissionOpensAt || !event.submissionClosesAt) {
    return {
      isOpen: false,
      opensAt: null,
      closesAt: null,
      reason: "Submission window not configured",
    }
  }

  // Check if current time is within the window
  const now = new Date()
  const opensAt = new Date(event.submissionOpensAt)
  const closesAt = new Date(event.submissionClosesAt)

const [submitSuccess, setSubmitSuccess] = useState(false)

const submitScore = useServerFn(submitAthleteScoreFn)

// Load initial data
useEffect(() => {
  async function loadData() {
    setLoading(true)
    setError(null)
    try {
      const [windowRes, scoreRes, workoutRes] = await Promise.all([
        getSubmissionWindowStatusFn({
          data: { competitionId, trackWorkoutId },
        }),
        getAthleteEventScoreFn({
          data: { competitionId, trackWorkoutId },
        }),
        getEventWorkoutDetailsFn({
          data: { competitionId, trackWorkoutId },
        }),
      ])

      setWindowStatus(windowRes)
      setExistingScore(scoreRes)
      setWorkoutDetails(workoutRes)

      // Pre-fill form if there's an existing score
      if (scoreRes.displayScore) {
        setScoreInput(scoreRes.displayScore)
        setStatus((scoreRes.status as "scored" | "cap") || "scored")
        if (scoreRes.secondaryValue !== null) {
          setSecondaryScore(String(scoreRes.secondaryValue))
        }
      }
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to load submission data",
      )
    } finally {
      setLoading(false)
    }
  }

  loadData()
}, [competitionId, trackWorkoutId])

// Parse score input
useEffect(() => {
  if (!workoutDetails || !scoreInput.trim()) {
    setParseResult(null)
    return
  }

  const result = parseScore(scoreInput, workoutDetails.scheme)
  setParseResult(result)
}, [scoreInput, workoutDetails])

const handleSubmit = async () => {
  if (!workoutDetails) return

  setSubmitting(true)
  setSubmitSuccess(false)
  setError(null)

  try {
    await submitScore({
      data: {
        competitionId,
        trackWorkoutId,
        score: scoreInput,
        status,
        secondaryScore: secondaryScore || undefined,
        tiebreakScore: tiebreakScore || undefined,
      },
    })

    setSubmitSuccess(true)
    // Refresh existing score
    const scoreRes = await getAthleteEventScoreFn({
      data: { competitionId, trackWorkoutId },
    })
    setExistingScore(scoreRes)

    // Clear success message after 3 seconds
    setTimeout(() => setSubmitSuccess(false), 3000)
  } catch (err) {
    setError(err instanceof Error ? err.message : "Failed to submit score")
  } finally {
    setSubmitting(false)
  }
}

if (loading) {
  return (
    <Card>
      <CardContent className="flex items-center justify-center py-8">
        <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
      </CardContent>
    </Card>
  )

