    athletes.sort((a, b) => {
      if (a.divisionLabel !== b.divisionLabel) {
        return a.divisionLabel.localeCompare(b.divisionLabel)
      }
      const aName = a.teamName || a.lastName
      const bName = b.teamName || b.lastName
      return aName.localeCompare(bName)
    })

