        id: trackWorkout.id,
        trackOrder: trackWorkout.trackOrder,
        pointsMultiplier: trackWorkout.pointsMultiplier,
        workout: trackWorkout.workout,
      },
      athletes,
      divisions: divisions.sort((a, b) => a.position - b.position),
    }
